<?php namespace App\Services; use App\Models\ActivityLog; use Illuminate\Support\Facades\Auth; use Illuminate\Database\Eloquent\Model; use Illuminate\Support\Collection; class ActivityLogService { public function log(string $action, Model $model = null, array $details = []): ActivityLog { return ActivityLog::create([ 'user_id' => Auth::id(), 'action' => $action, 'model_type' => $model ? get_class($model) : null, 'model_id' => $model ? $model->id : null, 'details' => json_encode($details), 'ip_address' => request()->ip(), 'user_agent' => request()->userAgent(), ]); } public function getLogs(array $filters = []): Collection { $query = ActivityLog::query(); if (isset($filters['user_id'])) { $query->where('user_id', $filters['user_id']); } if (isset($filters['action'])) { $query->where('action', 'like', '%' . $filters['action'] . '%'); } if (isset($filters['model_type'])) { $query->where('model_type', $filters['model_type']); } return $query->latest()->get(); } public function deleteOldLogs(int $days = 30): int { return ActivityLog::where('created_at', '<', now()->subDays($days))->delete(); } }